def analyze_macro_and_relative_strength(cpi_yoy, gdp_qoq, xle_ytd, xlf_ytd):
    ratio = xle_ytd / xlf_ytd if xlf_ytd != 0 else float('inf')
    if cpi_yoy > 3.0 and gdp_qoq < 2.0:
        cycle = 'Stagflation'
    elif cpi_yoy < 2.5 and gdp_qoq > 2.5:
        cycle = 'Expansion'
    elif cpi_yoy > 3.0 and gdp_qoq > 2.5:
        cycle = 'Overheat'
    else:
        cycle = 'Slowdown/Recession'
    return {'cycle': cycle, 'ratio': ratio, 'xle_ytd': xle_ytd, 'xlf_ytd': xlf_ytd}
